import re

def detect_code_hallucination(message_content):
    # Common hallucination patterns
    patterns = [
        r'File .* does not exist', 
        r'Package .* not found',
        r'Error: .*undefined'
    ]
    suspicious_phrases = [
        'I found the file', 'Package installed successfully',
        'Data shows clearly'
    ]

    content = message_content.lower()
    for phrase in suspicious_phrases:
        if phrase in content and not any(re.search(p, content) for p in patterns):
            return {'hallucination': True, 'confidence': 0.8}
    return {'hallucination': False}

