    (msg.content[0].text.value.includes('I don't') || 
     msg.content[0].text.value.includes('unclear'))
  );

  if (messageCount > 50 && recentErrors.length > 2) {
    return { hallucination: true, metric: 'thread_overflow', score: 0.9 };
  }
  return { hallucination: false };
