from openai import OpenAI
from pydantic import BaseModel, ValidationError

class UserQuery(BaseModel):
    user_id: int
    query: str

client = OpenAI()

def safe_tool_execution(run):
    if run.required_action:
        for tool_call in run.required_action.submit_tool_outputs.tool_calls:
            try:
                args = json.loads(tool_call.function.arguments)
                UserQuery(**args)  # Validates against schema
                # Submit valid tool output
            except (json.JSONDecodeError, ValidationError) as e:
                # Return corrective tool output
                corrective_output = {
                    'tool_call_id': tool_call.id,
                    'output': json.dumps({'error': 'Invalid arguments provided'})
                }
                client.beta.threads.runs.submit_tool_outputs(
                    thread_id=run.thread_id,
                    run_id=run.id,
                    tool_outputs=[corrective_output]
                )

SAFE_PACKAGES = {'pandas', 'numpy', 'matplotlib'}
SAFE_FILES = {'/tmp/data.csv'}

def sandboxed_code_execution(message):
    if message.tool_calls:
        for tool_call in message.tool_calls:
            if tool_call.type == 'code_interpreter':
                code = tool_call.code_interpreter.input
                # Block dangerous imports
                if 'os.system' in code or 'exec(' in code:
                    return 'Blocked: unsafe code execution'

                # Verify package imports
                imports = re.findall(r'import\s+(\w+)', code)
                invalid_packages = [pkg for pkg in imports if pkg not in SAFE_PACKAGES]
                if invalid_packages:
                    return f'Blocked packages: {invalid_packages}'
    return 'Code verified safe'

async function resetThreadContext(threadId: string) {
  const messages = await client.beta.threads.messages.list(threadId);

  if (messages.data.length > 75) {
    // Keep only last 25 messages
    const messagesToDelete = messages.data.slice(25);

    for (const message of messagesToDelete) {
      await client.beta.threads.messages.del(threadId, message.id);
    }

    // Add context summary
    await client.beta.threads.messages.create(threadId, {
      role: 'user',
      content: 'CONTEXT SUMMARY: Previous conversation archived. Continue from here.'
    });
  }
}
